parameters.jsCode:
// Access the nested array
const tactics = $input.all()[0].json.output.tactics;

// Map them into the standard n8n { json: {} } format
return tactics.map(t => {
  return {
    json: {
      description: t.tactic_description
    }
  };
});

// 1. Get all incoming items
const items = $input.all();

// 2. Clean the data for valid items
items.forEach((item) => {
  if (item.json.output && item.json.output.narration_content) {
    item.json.output.narration_content = item.json.output.narration_content.replace(/\r|\n|\t/g, '');
  }
});

// 3. Return only items that have the 'output' property and NO 'error' property
return items.filter(item => {
  return item.json.output && !item.json.error;
});

